import{_ as a,c as r,o,aN as t}from"./chunks/framework.BRm39z_l.js";const d=JSON.parse('{"title":"RocketMQ基础","description":"","frontmatter":{},"headers":[],"relativePath":"middleware/01. RocketMQ/01.RocketMQ基础.md","filePath":"middleware/01. RocketMQ/01.RocketMQ基础.md"}'),i={name:"middleware/01. RocketMQ/01.RocketMQ基础.md"};function l(h,e,s,c,n,p){return o(),r("div",null,e[0]||(e[0]=[t('<h1 id="rocketmq基础" tabindex="-1">RocketMQ基础 <a class="header-anchor" href="#rocketmq基础" aria-label="Permalink to &quot;RocketMQ基础&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#为什么要用消息队列">为什么要用消息队列</a><ul><li><a href="#解耦">解耦</a></li><li><a href="#异步">异步</a></li><li><a href="#削峰">削峰</a></li></ul></li><li><a href="#对-rocketmq-的理解">对 RocketMQ 的理解</a></li><li><a href="#消息队列有哪些模型">消息队列有哪些模型</a><ul><li><a href="#队列模型">队列模型</a></li><li><a href="#发布-订阅模型">发布/订阅模型</a></li></ul></li><li><a href="#rocketmq-的消息模型">RocketMQ 的消息模型</a><ul><li><a href="#message">Message</a></li><li><a href="#topic">Topic</a></li><li><a href="#tag">Tag</a></li><li><a href="#group">Group</a></li><li><a href="#message-queue">Message Queue</a></li><li><a href="#offset">Offset</a></li></ul></li><li><a href="#消息的消费模式">消息的消费模式</a></li><li><a href="#rocketmq-的基本架构">RocketMQ 的基本架构</a><ul><li><a href="#nameserver">NameServer</a></li><li><a href="#broker">Broker</a></li><li><a href="#producer">Producer</a></li><li><a href="#consumer">Consumer</a></li></ul></li><li><a href="#rocketmq-在这个项目中有哪些弊端">RocketMQ 在这个项目中有哪些弊端</a><ul><li><a href="#系统复杂度提升">系统复杂度提升</a></li><li><a href="#一致性问题更难">一致性问题更难</a></li><li><a href="#消息重复、乱序、堆积">消息重复、乱序、堆积</a></li><li><a href="#运维成本增加">运维成本增加</a></li></ul></li></ul></nav><h2 id="为什么要用消息队列" tabindex="-1">为什么要用消息队列 <a class="header-anchor" href="#为什么要用消息队列" aria-label="Permalink to &quot;为什么要用消息队列&quot;">​</a></h2><h3 id="解耦" tabindex="-1">解耦 <a class="header-anchor" href="#解耦" aria-label="Permalink to &quot;解耦&quot;">​</a></h3><p>生产者将消息放入消息队列，消费者从队列中取出消息，这样生产者与消费者就不会直接进行通信，这样也就实现了解耦，生产者只生产消息，消费者只消费消息</p><p>我的项目中的图片审批，就用了 RocketMQ 来做了解耦</p><h3 id="异步" tabindex="-1">异步 <a class="header-anchor" href="#异步" aria-label="Permalink to &quot;异步&quot;">​</a></h3><p>系统可以将那些耗时的任务放在消息队列中异步处理，以此达到快速响应用户请求的目的</p><p>比如说电商平台中，用户下单后，可以先返回一个下单成功的消息，然后将订单信息放在消息队列中，后台再去处理订单信息</p><h3 id="削峰" tabindex="-1">削峰 <a class="header-anchor" href="#削峰" aria-label="Permalink to &quot;削峰&quot;">​</a></h3><p>用于应对系统高并发请求的瞬时流量高峰，通过消息队列，可以将瞬时的高峰流量转化为持续的低流量，从而保护系统不会因为瞬时的高流量而崩溃</p><p>用户将请求发送到系统后，由生产者接受并转换为消息，发送到 RocketMQ 中，队列用来充当缓存区，将大量请求按顺序排队，这样就可以削减请求高峰时对后端服务的直接压力</p><p>消费者从 RocketMQ 队列中按照一定速率读取消息并进行处理。可以根据后端处理能力和当前负载情况动态调整消费者的消费速率，达到填谷的效果</p><h2 id="对-rocketmq-的理解" tabindex="-1">对 RocketMQ 的理解 <a class="header-anchor" href="#对-rocketmq-的理解" aria-label="Permalink to &quot;对 RocketMQ 的理解&quot;">​</a></h2><p>RocketMQ 是阿里巴巴开源的一款分布式消息中间件，具有高吞吐量、低延迟和高可用性，其主要组件包括生产者、消费者、Brocker、Topic 和队列，消息由生产者发送到 Brocker，再根据路由规则存储到队列中，消费者从队列中拉取消息进行处理。适用于异步解耦和流量削峰等场景</p><h2 id="消息队列有哪些模型" tabindex="-1">消息队列有哪些模型 <a class="header-anchor" href="#消息队列有哪些模型" aria-label="Permalink to &quot;消息队列有哪些模型&quot;">​</a></h2><h3 id="队列模型" tabindex="-1">队列模型 <a class="header-anchor" href="#队列模型" aria-label="Permalink to &quot;队列模型&quot;">​</a></h3><p>这是一种发-存-收的模型，生产者往某个队列里发送消息，消费者从队列里获取消息，一个队列可以存储多个生产者的消息，也可以有多个消费者，但是消费者之间为竞争关系，换句话说，一个消息只能由一个消费者消费</p><h3 id="发布-订阅模型" tabindex="-1">发布/订阅模型 <a class="header-anchor" href="#发布-订阅模型" aria-label="Permalink to &quot;发布/订阅模型&quot;">​</a></h3><p>发布 - 订阅模型中，消息的发送方称为发布者（Publisher），消息的接收方称为订阅者（Subscriber），服务端存放消息的容器称为主题（Topic）</p><p>发布者将消息发送到主题中，订阅者接收消息前需要先订阅主题，订阅既是一个动作，同时也是主体在消费时创建的逻辑副本，每份订阅中，订阅者都可以接收到主题的所有消息</p><h2 id="rocketmq-的消息模型" tabindex="-1">RocketMQ 的消息模型 <a class="header-anchor" href="#rocketmq-的消息模型" aria-label="Permalink to &quot;RocketMQ 的消息模型&quot;">​</a></h2><p>RocketMQ 本身的消息是由下面几部分组成</p><h3 id="message" tabindex="-1">Message <a class="header-anchor" href="#message" aria-label="Permalink to &quot;Message&quot;">​</a></h3><p>message 为要传输的消息</p><p>一个消息必须要有一个主题，主题可以看作是他要发送到的地址</p><h3 id="topic" tabindex="-1">Topic <a class="header-anchor" href="#topic" aria-label="Permalink to &quot;Topic&quot;">​</a></h3><p>topic 可以看作消息的归类，是消息的第一级类型</p><p>topic 可以有多个生产者向他发送消息，可以被多个消费者订阅，一个生产者也可以向不同的 topic 发送消息</p><h3 id="tag" tabindex="-1">Tag <a class="header-anchor" href="#tag" aria-label="Permalink to &quot;Tag&quot;">​</a></h3><p>tag 可以看作子主题，它是消息的第二级类型，用于为用户提供额外的灵活性</p><p>使用标签，同一业务模块不同目的的消息就可以用相同 Topic 而不同的 <strong>Tag</strong> 来标识</p><h3 id="group" tabindex="-1">Group <a class="header-anchor" href="#group" aria-label="Permalink to &quot;Group&quot;">​</a></h3><p>订阅者的概念是通过消费组来体现的，每个消费组都消费主题中一份完整的消息，不同消费组之间的消费进度彼此独立</p><p>消费组中包含多个消费者，同一个组中的消费者是竞争消费关系</p><h3 id="message-queue" tabindex="-1">Message Queue <a class="header-anchor" href="#message-queue" aria-label="Permalink to &quot;Message Queue&quot;">​</a></h3><p>一个 Topic 下可以设置多个消息队列，Topic 包括多个 Message Queue，如果一个 Consumer 需要获取 Topic 下所有的消息，就要遍历所有的 Message Queue。</p><h3 id="offset" tabindex="-1">Offset <a class="header-anchor" href="#offset" aria-label="Permalink to &quot;Offset&quot;">​</a></h3><p>在 Topic 的消费过程中，由于消息需要被不同的组进行多次消费，所以消费完的消息并不会立即被删除，这就需要 RocketMQ 为每个消费组在每个队列上维护一个消费位置，这个位置之前的消息都被消费过，之后的消息都没有被消费过，每成功消费一条消息，消费位置就加一。</p><p>也可以这么说，<code>Queue</code> 是一个长度无限的数组，<strong>Offset</strong> 就是下标</p><h2 id="消息的消费模式" tabindex="-1">消息的消费模式 <a class="header-anchor" href="#消息的消费模式" aria-label="Permalink to &quot;消息的消费模式&quot;">​</a></h2><p>消费模式有两种：<strong>Clustering</strong>（集群消费）和<strong>Broadcasting</strong>（广播消费）</p><p>默认为集群消费，一个消费者组共同消费一个主题的多个队列，一个队列只会被一个消费者消费，如果一个消费者失效，分组内其他的消费者会顶替</p><p>广播消费消息会发给消费者组中的每一个消费者进行消费</p><h2 id="rocketmq-的基本架构" tabindex="-1">RocketMQ 的基本架构 <a class="header-anchor" href="#rocketmq-的基本架构" aria-label="Permalink to &quot;RocketMQ 的基本架构&quot;">​</a></h2><p><img src="https://cdn.domye.top/uploads/10/1761650614.webp" alt="" loading="lazy"></p><p>RocketMQ 一共有四个部分组成：NameServer，Broker，Producer 生产者，Consumer 消费者，它们对应了：发现、发、存、收，为了保证高可用，一般每一部分都是集群部署的</p><p>如果类比，生产者消费者就是发信者和收信者，broker 就是邮局，NameServer 则是负责协调各个邮局的管理机构</p><h3 id="nameserver" tabindex="-1">NameServer <a class="header-anchor" href="#nameserver" aria-label="Permalink to &quot;NameServer&quot;">​</a></h3><p>每个 NameServer 结点之间是相互独立，彼此没有任何信息交互。</p><p>Nameserver 被设计成几乎是无状态的，通过部署多个结点来标识自己是一个伪集群</p><p>Producer 在发送消息前从 NameServer 中获取 Topic 的路由信息，也就是发往哪个 Broker</p><p>Consumer 也会定时从 NameServer 获取 Topic 的路由信息</p><p>Broker 在启动时会向 NameServer 注册，并定时进行心跳连接，且定时同步维护的 Topic 到 NameServer</p><h3 id="broker" tabindex="-1">Broker <a class="header-anchor" href="#broker" aria-label="Permalink to &quot;Broker&quot;">​</a></h3><p>负责存储和转发消息</p><p>Broker 内部维护着一个个 Consumer Queue，用来存储消息的索引，真正存储消息的地方为 CommitLog</p><p>单个 Broker 与所有的 Nameserver 保持着长连接和心跳，并会定时将 Topic 信息同步到 NameServer，和 NameServer 的通信底层是通过 Netty 实现的</p><h3 id="producer" tabindex="-1">Producer <a class="header-anchor" href="#producer" aria-label="Permalink to &quot;Producer&quot;">​</a></h3><p><strong>Producer</strong>由用户进行分布式部署，消息由<strong>Producer</strong>通过多种负载均衡模式发送到<strong>Broker</strong>集群，发送低延时，支持快速失败。</p><p><strong>RocketMQ</strong> 提供了三种方式发送消息：同步、异步和单向</p><p><strong>同步发送</strong>：同步发送指消息发送方发出数据后会在收到接收方发回响应之后才发下一个数据包。一般用于重要通知消息</p><p><strong>异步发送</strong>：异步发送指发送方发出数据后，不等接收方发回响应，接着发送下个数据包，一般用于可能链路耗时较长而对响应时间敏感的业务场景</p><p><strong>单向发送</strong>：单向发送是指只负责发送消息而不等待服务器回应且没有回调函数触发，适用于某些耗时非常短但对可靠性要求并不高的场景</p><h3 id="consumer" tabindex="-1">Consumer <a class="header-anchor" href="#consumer" aria-label="Permalink to &quot;Consumer&quot;">​</a></h3><p><strong>Consumer</strong>也由用户部署，支持 push 和 pull 两种消费模式，支持集群消费覅和广播消费</p><p><strong>PULL</strong>为主动从消息服务器拉去信息，只要批量拉取到消息，用户应用会启动消费过程</p><p><strong>Push</strong>推送型消费者封装了消息的拉取、消费进度和其他的内部维护工作，将消息到达时执行的回调接口留给用户应用程序来实现，不同于 Pull 的是 Push 首先要注册消费监听器，当监听器处触发后才开始消费消息</p><h2 id="rocketmq-在这个项目中有哪些弊端" tabindex="-1">RocketMQ 在这个项目中有哪些弊端 <a class="header-anchor" href="#rocketmq-在这个项目中有哪些弊端" aria-label="Permalink to &quot;RocketMQ 在这个项目中有哪些弊端&quot;">​</a></h2><h3 id="系统复杂度提升" tabindex="-1">系统复杂度提升 <a class="header-anchor" href="#系统复杂度提升" aria-label="Permalink to &quot;系统复杂度提升&quot;">​</a></h3><p>引入 MQ 后，系统从同步调用变成异步链路，排查问题更复杂。</p><h3 id="一致性问题更难" tabindex="-1">一致性问题更难 <a class="header-anchor" href="#一致性问题更难" aria-label="Permalink to &quot;一致性问题更难&quot;">​</a></h3><p>数据库事务提交了，不代表消息一定成功消费；消息成功发出，也不代表业务一定处理成功。</p><h3 id="消息重复、乱序、堆积" tabindex="-1">消息重复、乱序、堆积 <a class="header-anchor" href="#消息重复、乱序、堆积" aria-label="Permalink to &quot;消息重复、乱序、堆积&quot;">​</a></h3><ul><li>至少一次投递会导致重复消费</li><li>并发消费可能带来顺序问题</li><li>消费能力不足会消息堆积</li></ul><h3 id="运维成本增加" tabindex="-1">运维成本增加 <a class="header-anchor" href="#运维成本增加" aria-label="Permalink to &quot;运维成本增加&quot;">​</a></h3><p>需要维护 Broker、NameServer、监控、告警。</p>',77)]))}const m=a(i,[["render",l]]);export{d as __pageData,m as default};
